    int32_t ndim = shape.GetDimNum();
    if (dim < 0) dim += ndim;
    uint32_t seqLen = static_cast<uint32_t>(shape.GetDim(static_cast<uint32_t>(dim)));

    // Tile length: we need two buffers (x and mask) of tileLen floats each
